sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below

function openModalForm() {

	//HT - STRY0057620


	//the GlideAjax call is needed to pass values for the record with the below sys_id to the addParm('sysparm_query'...)
	//the values from the sysparm_query initialize the default values in the GlideModalForm
	var parentSysId = g_form.getUniqueValue();

	var ajax = new GlideAjax('ClientTaskerEmailScripts');
	ajax.addParam('sysparm_name', 'populateTaskerEmailForm');
	ajax.addParam('sysparm_sysId', parentSysId);


	ajax.getXML(function(response){
		try{
			// If the form is dirty, ask the user if they would like to save the record
			var saveChangeConfirmation = false;
			var saveMsg = getMessage('Tasker - Modal Save Changes Message');
			if(typeof spModal != 'undefined'){
				var serializeChanges = g_form.serialize(true);
				if(serializeChanges.length>0){
					var changeFieldList = [];
					for (var field in serializeChanges) {
						changeFieldList.push(serializeChanges[field].label.trim());
					}
					var fMsg = changeFieldList.join(', ');					
					saveMsg += "  " + fMsg;
					saveChangeConfirmation = true;
				}
			} else if (typeof spModal == 'undefined' && g_form.modified) {
				saveMsg += JSON.stringify(g_form.modifiedFields);
				saveChangeConfirmation = true;
			}

			// use the variable set above here to show confirmation message.
			if(saveChangeConfirmation){				
				if(confirm(saveMsg)){
					g_form.save();
				} else{
					return false;
				}
			}


			var data = response.responseXML.documentElement.getAttribute("answer");
			var exportAttachmentsOrDocs = JSON.parse(data);

			//the values related to attachments and documents or boolean values coming from the script include "ClientTaskerEmailScripts"
			// we use these values to determine if the checkboxes will be visible or not
			//the taskNumber is used for populating the default subject and body
			//the userName is use forthe deafult body of the email
			var enableMyAttachments = exportAttachmentsOrDocs.exportAttachments;
			var enableAllSharedDocs = exportAttachmentsOrDocs.exportAllSharedAttachments;
			var enableMyDocs = exportAttachmentsOrDocs.exportMyDocs;
			var enableAttachAndDocs = exportAttachmentsOrDocs.exportAllSharedDocuments;
			var subject = exportAttachmentsOrDocs.subject.toString();
			var body = exportAttachmentsOrDocs.body.toString();
			var recipients = exportAttachmentsOrDocs.recipients;
			//GlideModalForm displays a form as a modal 
			//the addParm function takes the values from the record and initializes the form fields to the specified values
			//if any of the fields is not included in addParm query that field will not be editable in the modal
			var modalForm = new GlideModalForm(getMessage('Tasker - Email Task Information'), 'x_153465_discovert_tasker_email');
			modalForm.addParm('sysparm_query','parent='+parentSysId + '^u_subject='+subject +
			'^u_export_my_attachments=false^u_export_all_shared_attachments=false^u_export_my_documents=false^u_export_all_shared_documents=false^u_body='+body+'^u_recipient='+recipients);

			modalForm.render();
			modalForm.setSysID(-1);

		}catch(e){
			jslog(e);
		}
	});
}
